// src/components/TelaLogs.jsx
import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

export default function TelaLogs() {
  const { user } = useAuth();
  const token = user.token;
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/logs', {
      headers: { Authorization: `Bearer ${token}` }
    })
    .then(res => setLogs(res.data))
    .catch(() => setLogs([]))
    .finally(() => setLoading(false));
  }, [token]);

  if (loading) return <div>Carregando logs...</div>;
  if (!logs.length) return <div>Nenhum log encontrado.</div>;

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold mb-4">Logs do Sistema</h2>
      <table className="min-w-full border">
        <thead>
          <tr>
            <th>ID</th>
            <th>Data/Hora</th>
            <th>Usuário</th>
            <th>Ação</th>
            <th>Entidade</th>
            <th>ID Entidade</th>
            <th>Detalhes</th>
          </tr>
        </thead>
        <tbody>
          {logs.map(log => (
            <tr key={log.id}>
              <td>{log.id}</td>
              <td>{new Date(log.criado_em).toLocaleString('pt-BR')}</td>
              <td>{log.usuario_nome} (ID: {log.usuario_id})</td>
              <td>{log.acao}</td>
              <td>{log.entidade}</td>
              <td>{log.entidade_id}</td>
              <td>
                <pre className="text-xs whitespace-pre-wrap">{log.detalhes}</pre>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
